import { useEffect, useRef, useState } from 'react';
import './win.css';

/* ─────────────────────────────────────────────────────────────────────────
 * WinModal — the satisfying completion card.
 *
 * Shows: time, mistakes, hints used, difficulty + a streak/perfect badge.
 * If the player solved without mistakes or hints we award a "Perfect" star.
 * If they have an active daily streak we surface its day-count.
 *
 * The modal is lazy-loaded in EngineSlot only when `puzzleSolved` fires, so
 * the bundle delta on first-paint is roughly the import statement plus
 * tree-shaken runtime for the rest of the chunk.
 *
 * Reduced motion bypasses the grid-color-wave that paints across the
 * background grid — the modal itself fades in.
 * ───────────────────────────────────────────────────────────────────────── */

export interface WinPayload {
  difficulty: string;
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
  streak?: number;
}

interface Props {
  win: WinPayload;
  onClose: () => void;
  onNewGame?: () => void;
}

function format(ms: number): string {
  const total = Math.floor(ms / 1000);
  const m = Math.floor(total / 60);
  const s = total % 60;
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

export function WinModal({ win, onClose, onNewGame }: Props) {
  const [reveal, setReveal] = useState(false);
  const closeRef = useRef<HTMLButtonElement>(null);
  const perfect = win.mistakes === 0 && win.hintsUsed === 0;

  useEffect(() => {
    const t = setTimeout(() => setReveal(true), 30);
    setTimeout(() => closeRef.current?.focus(), 250);
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') { e.preventDefault(); onClose(); }
    }
    document.addEventListener('keydown', onKey);
    return () => { clearTimeout(t); document.removeEventListener('keydown', onKey); };
  }, [onClose]);

  return (
    <div
      className="win-backdrop"
      role="dialog"
      aria-modal="true"
      aria-label="Puzzle solved"
      onClick={onClose}
    >
      <div
        className={`win-card${reveal ? ' shown' : ''}${perfect ? ' perfect' : ''}`}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="win-burst" aria-hidden="true">
          <span />
          <span />
          <span />
          <span />
          <span />
        </div>
        <p className="win-eyebrow">{perfect ? 'Perfect win' : 'Solved'}</p>
        <h2 className="win-title">{format(win.timeMs)}</h2>
        <p className="win-diff">{win.difficulty}</p>
        <div className="win-stats">
          <div className="win-stat">
            <span className="win-stat-value">{win.mistakes}</span>
            <span className="win-stat-label">Mistakes</span>
          </div>
          <div className="win-stat">
            <span className="win-stat-value">{win.hintsUsed}</span>
            <span className="win-stat-label">Hints</span>
          </div>
          {win.streak != null && win.streak > 0 && (
            <div className="win-stat">
              <span className="win-stat-value">{win.streak}🔥</span>
              <span className="win-stat-label">Streak</span>
            </div>
          )}
        </div>

        {perfect && (
          <div className="win-badge" aria-label="Perfect difficulty badge">
            <span className="win-badge-star">★</span>
            <span className="win-badge-text">{win.difficulty} · perfect</span>
          </div>
        )}

        <div className="win-actions">
          <button
            ref={closeRef}
            className="win-btn ghost"
            onClick={onClose}
          >Close</button>
          {onNewGame && (
            <button
              className="win-btn primary"
              onClick={() => { onClose(); onNewGame(); }}
            >New game</button>
          )}
        </div>
      </div>
    </div>
  );
}
